parameters.prompt:
=Create a square 1:1 visual preview for the production pipeline.

If this is a Visual Production Bot v2.1 composer-prep payload, do not treat the task as one random final banner. Create a clean temporary preview based on the described layers. The real pixel-perfect composer will be connected as a separate service later.

Project: {{ $json.project }}
Mode: {{ $json.visual_mode }}

Payload / prompt:
{{ $json.image_prompt }}

Post text / source task:
{{ $json.final_post }}

Constraints:
- do not add long small text to the image;
- avoid unreadable Russian lettering;
- do not add random logos or watermarks.

parameters.jsCode:
return items.map((item) => {
  const j = item.json || {};
  const rawText = String(j.raw_text || j.text || '').trim();
  const photoFileId = String(j.photo_file_id || '');
  return {
    json: {
      ...j,
      chat_id: String(j.chat_id || ''),
      user_id: String(j.user_id || ''),
      username: j.username || '',
      source_type: j.source_type || (photoFileId ? 'photo' : 'text'),
      raw_text: rawText,
      text: rawText,
      has_photo: Boolean(j.has_photo === true || j.has_photo === 'true' || photoFileId),
      photo_file_id: photoFileId
    }
  };
});

return items.map((item) => {
  const j = item.json || {};
  const text = String(j.raw_text || j.text || '').toLowerCase();
  const hasPhoto = Boolean(j.has_photo || j.photo_file_id);
  const hasAny = (...words) => words.some((w) => text.includes(w));
  const mentionsVisual = hasAny('картин', 'визуал', 'постер', 'афиш', 'баннер', 'изображ', 'листовк', 'флаер', 'poster', 'banner', 'image') || hasPhoto;
  const mentionsPay = hasAny('pay', 'пэй', 'оплат', 'яндекс-яндекс', 'yandex-yandex');
  const mentionsMonopoly = hasAny('монопол', 'monopoly');
  const mentionsCasper = hasAny('casper', 'каспер');
  const mentionsHockey = hasAny('хоккей', 'gorilla', 'горилл', 'тренировк', 'афиш', 'постер', 'листовк', 'печать', 'a4', 'a5');

  let projectKey = 'dnk';
  if (mentionsPay) projectKey = 'monopoly_pay';
  else if (mentionsMonopoly) projectKey = 'monopoly';
  else if (mentionsCasper) projectKey = 'casper';
  else if (mentionsHockey) projectKey = 'gorilla_hockey';

  let visualMode = 'post_generation';
  if (projectKey === 'monopoly' || projectKey === 'monopoly_pay') visualMode = 'composer';
  else if (projectKey === 'casper') visualMode = 'style_generation';
  else if (projectKey === 'gorilla_hockey') {
    if (hasPhoto) visualMode = 'hockey_photo_template';
    else if (hasAny('листовк', 'печать', 'a4', 'a5')) visualMode = 'hockey_print_layout';
    else if (hasAny('афиш')) visualMode = 'hockey_print_layout';
    else visualMode = 'hockey_generated_poster';
  }

  const hasToken = (token) => new RegExp('(^|[^a-z0-9\\u0430-\\u044f])' + token + '($|[^a-z0-9\\u0430-\\u044f])', 'iu').test(text);
  let outputFormat = 'square';
  if (hasAny('\u0441\u0442\u043e\u0440\u0438\u0441', 'story', '1080x1920')) outputFormat = 'story';
  else if (hasToken('vk') || hasToken('\u0432\u043a') || hasAny('1080x1350')) outputFormat = 'vk_post';
  else if (hasToken('a4') || hasToken('\u04304')) outputFormat = 'print_a4';
  else if (hasToken('a5') || hasToken('\u04305')) outputFormat = 'print_a5';

  const isVisualRequest = Boolean(mentionsVisual || ['monopoly','monopoly_pay','casper','gorilla_hockey'].includes(projectKey));
  return {
    json: {
      ...j,
      is_visual_request: isVisualRequest,
      project_key: projectKey,
      project: projectKey,
      visual_mode: visualMode,
      output_format: outputFormat,
      needs_text_layer: ['composer','hockey_photo_template','hockey_print_layout'].includes(visualMode) || mentionsVisual,
      needs_illustration_layer: ['composer','style_generation','hockey_generated_poster'].includes(visualMode),
      needs_background_layer: ['composer','hockey_print_layout'].includes(visualMode),
      needs_uploaded_photo: visualMode === 'hockey_photo_template',
      task_text: String(j.raw_text || j.text || '').trim()
    }
  };
});

return items.map((item) => {
  const j = item.json || {};
  const task = String(j.task_text || j.raw_text || j.text || '').trim();
  const isComposer = j.visual_mode === 'composer';
  const isCasper = j.visual_mode === 'style_generation';
  const visualJob = {
    job_type: 'visual_production',
    project_key: j.project_key,
    visual_mode: j.visual_mode,
    source_text: task,
    output_format: j.output_format || 'square',
    text_layer: {
      enabled: Boolean(j.needs_text_layer),
      prompt: 'Generate a short readable Russian image headline and optional subheadline for: ' + task,
      generated_text: '',
      position: '',
      style: j.text_style_rules || ''
    },
    illustration_layer: {
      enabled: Boolean(j.needs_illustration_layer),
      prompt: 'Create an illustration layer for: ' + task + '. Style: ' + (j.image_style_rules || ''),
      asset_ref: '',
      locked: false
    },
    background_layer: {
      enabled: Boolean(j.needs_background_layer),
      prompt: 'Use or generate a background according to asset rules: ' + (j.asset_rules || ''),
      asset_ref: '',
      locked: false
    },
    layout: {
      variant: 'auto',
      composition_rules: j.composition_rules || ''
    },
    profile: {
      text_style_rules: j.text_style_rules || '',
      image_style_rules: j.image_style_rules || '',
      composition_rules: j.composition_rules || '',
      negative_rules: j.negative_rules || ''
    },
    revision_state: {
      can_change_text: true,
      can_change_illustration: true,
      can_change_background: true,
      can_change_layout: true
    }
  };
  let imagePrompt;
  if (isComposer) {
    imagePrompt = [
      'Visual Production Bot v2.1 composer-prep stage.',
      'Do not treat this as a final one-prompt banner. Prepare a controlled preview from separate layers: text_layer, illustration_layer, background_layer and layout.',
      'Project: ' + j.project_name + ' (' + j.project_key + ').',
      'Task: ' + task,
      'Text layer prompt: ' + visualJob.text_layer.prompt,
      'Illustration layer prompt: ' + visualJob.illustration_layer.prompt,
      'Background layer prompt: ' + visualJob.background_layer.prompt,
      'Composition rules: ' + (j.composition_rules || ''),
      'Negative rules: ' + (j.negative_rules || ''),
      'Temporary limitation: real pixel-perfect composer service is not connected yet; keep the preview clean and avoid tiny unreadable Russian text.'
    ].join('
');
  } else if (isCasper) {
    imagePrompt = [
      'Generate a Casper style visual preview from project profile.',
      'Task: ' + task,
      'Style rules: ' + (j.image_style_rules || ''),
      'If Russian text is needed, keep it short and readable; final text layer should later be rendered by composer.',
      'Negative rules: ' + (j.negative_rules || '')
    ].join('
');
  } else {
    imagePrompt = [
      'Generate a hockey visual preview for mode ' + j.visual_mode + '.',
      'Task: ' + task,
      'Style rules: ' + (j.image_style_rules || ''),
      'Composition rules: ' + (j.composition_rules || ''),
      j.has_photo ? 'Uploaded photo file id is available for future template composer: ' + (j.photo_file_id || '') : '',
      'Temporary limitation: real photo/template/print composer service is not connected yet.'
    ].filter(Boolean).join('
');
  }
  return {
    json: {
      ...j,
      visual_job: visualJob,
      visual_job_json: JSON.stringify(visualJob),
      image_prompt: imagePrompt,
      image_text: '',
      final_post: task || (j.project_name + ' visual task'),
      action: 'approve'
    }
  };
});
